mapper.select:
SELECT d.*, COALESCE((SELECT MAX(v.ver_num) FROM wf_flow_version v WHERE v.flow_id = d.id AND v.status != 'draft'), (SELECT MAX(v.ver_num) FROM wf_flow_version v WHERE v.flow_id = d.id)) AS current_ver, EXISTS (SELECT 1 FROM wf_flow_version v WHERE v.flow_id = d.id AND v.status = 'active') AS has_published_version FROM wf_flow_definition d WHERE d.is_deleted = 0
AND (d.name LIKE CONCAT('%', #{keyword}, '%') OR d.flow_key LIKE CONCAT('%', #{keyword}, '%'))
AND d.status = #{status}
AND d.category = #{category}
ORDER BY d.updt_time DESC

SELECT d.*, COALESCE((SELECT MAX(v.ver_num) FROM wf_flow_version v WHERE v.flow_id = d.id AND v.status != 'draft'), (SELECT MAX(v.ver_num) FROM wf_flow_version v WHERE v.flow_id = d.id)) AS current_ver, EXISTS (SELECT 1 FROM wf_flow_version v WHERE v.flow_id = d.id AND v.status = 'active') AS has_published_version FROM wf_flow_definition d WHERE d.is_deleted = 0
AND (d.name LIKE CONCAT('%', #{keyword}, '%') OR d.flow_key LIKE CONCAT('%', #{keyword}, '%'))
AND d.status = #{status}
AND d.category = #{category}
ORDER BY d.updt_time DESC

mapper.update:
UPDATE wf_flow_definition
SET updt_time = #{updtTime}
, name = #{name}
, flow_key = #{flowKey}
, category = #{category}
, description = #{description}
, remark = #{remark}
, status = #{status}
, updated_by = #{updatedBy}
WHERE id = #{id}

