mapper.select:
SELECT c.* FROM wf_node_approval_config c
INNER JOIN wf_flow_node n ON n.id = c.node_id
WHERE n.version_id = #{versionId}

SELECT c.* FROM wf_node_auto_config c
INNER JOIN wf_flow_node n ON n.id = c.node_id
WHERE n.version_id = #{versionId}

SELECT c.* FROM wf_node_notify_config c
INNER JOIN wf_flow_node n ON n.id = c.node_id
WHERE n.version_id = #{versionId}

SELECT c.* FROM wf_node_condition_config c
INNER JOIN wf_flow_node n ON n.id = c.node_id
WHERE n.version_id = #{versionId}

SELECT r.* FROM wf_edge_cond_rule r
INNER JOIN wf_flow_edge e ON e.id = r.edge_id
WHERE e.version_id = #{versionId}
